+    #[test]
+    fn blit_to_painter_halfblock_maps_fg_and_bg() {
+        let mut fb = DoomFramebuffer::new(1, 2);
+        let top = PackedRgba::RED;
+        let bottom = PackedRgba::BLUE;
+        fb.set_pixel(0, 0, top);
+        fb.set_pixel(0, 1, bottom);
